import sysfrom pathlib import Pathimport numpy as npimport pandas as pdimport joblibfrom collections import Counter# Ensure project root is on sys.pathPROJECT_ROOT = Path(__file__).resolve().parents[1]if str(PROJECT_ROOT) not in sys.path:    sys.path.insert(0, str(PROJECT_ROOT))from config import (    PROCESSED_DATA_DIR,    BASELINE_MODELS_DIR,    TABLE_DIR,)DATASET_TAG = "large_lite"TEXT_COL = "full_text"LABEL_COL = "label_5d"def load_data_and_model():    df = pd.read_parquet(PROCESSED_DATA_DIR / "train_doc_5d_large_lite.parquet")    model = joblib.load(BASELINE_MODELS_DIR / "tfidf_logistic_large_lite.joblib")    return df, model# -------------------------# Step 1: Extract TF-IDF top terms# -------------------------def get_top_terms(model, top_n=50):    tfidf = model.named_steps["tfidf"]    clf = model.named_steps["clf"]    feature_names = tfidf.get_feature_names_out()    coefs = clf.coef_[0]    coef_df = pd.DataFrame({        "term": feature_names,        "coef": coefs,    })    top_positive = coef_df.sort_values("coef", ascending=False).head(top_n)    top_negative = coef_df.sort_values("coef", ascending=True).head(top_n)    return top_positive, top_negative# -------------------------# Step 2: Term frequency difference# -------------------------def compute_term_frequencies(df, terms):    pos_texts = df[df[LABEL_COL] == 1][TEXT_COL]    neg_texts = df[df[LABEL_COL] == 0][TEXT_COL]    def count_terms(texts):        counter = Counter()        for text in texts:            tokens = str(text).lower().split()            counter.update(tokens)        return counter    pos_counter = count_terms(pos_texts)    neg_counter = count_terms(neg_texts)    results = []    for term in terms:        pos_count = pos_counter[term]        neg_count = neg_counter[term]        total = pos_count + neg_count        if total == 0:            continue        pos_ratio = pos_count / total        results.append({            "term": term,            "pos_count": pos_count,            "neg_count": neg_count,            "pos_ratio": pos_ratio,        })    return pd.DataFrame(results)# -------------------------# Step 3: Combine coef + frequency# -------------------------def combine_analysis(top_terms_df, freq_df):    merged = top_terms_df.merge(freq_df, on="term", how="left")    # importance score    merged["importance"] = merged["coef"].abs() * np.log1p(        merged["pos_count"] + merged["neg_count"]    )    return merged.sort_values("importance", ascending=False)def main():    df, model = load_data_and_model()    print("Extracting top TF-IDF terms...")    top_pos, top_neg = get_top_terms(model, top_n=100)    print("Computing frequency differences...")    pos_freq = compute_term_frequencies(df, top_pos["term"])    neg_freq = compute_term_frequencies(df, top_neg["term"])    print("Combining analysis...")    pos_final = combine_analysis(top_pos, pos_freq)    neg_final = combine_analysis(top_neg, neg_freq)    TABLE_DIR.mkdir(parents=True, exist_ok=True)    pos_path = TABLE_DIR / "lexical_cues_positive_large_lite.csv"    neg_path = TABLE_DIR / "lexical_cues_negative_large_lite.csv"    pos_final.to_csv(pos_path, index=False)    neg_final.to_csv(neg_path, index=False)    print("\nSaved:")    print(pos_path)    print(neg_path)    print("\nTop positive cues:")    print(pos_final.head(10))    print("\nTop negative cues:")    print(neg_final.head(10))if __name__ == "__main__":    main()